@echo off
echo ==============================================
echo   SETUP: MS Rewards Farmer Daily Auto-Run
echo   (Can quyen Admin)
echo ==============================================
echo.

:: Create task with daily 8AM + at-logon triggers
schtasks /delete /tn "MS Rewards Farmer Daily" /f >nul 2>&1
schtasks /create /tn "MS Rewards Farmer Daily" /xml "%~dp0farm_task.xml" /f

if %errorlevel%==0 (
    echo.
    echo [OK] Task Scheduler da duoc cap nhat!
    echo     - Chay moi ngay luc 8:00 AM
    echo     - Chay khi dang nhap (sau 2 phut)
    echo     - Chay bu neu bi lo gio
) else (
    echo.
    echo [LOI] Khong the tao task. Hay chay file nay bang:
    echo       Right-click ^> Run as Administrator
)

echo.
pause

@echo off
cd /d "%~dp0"
echo ==============================================
echo   MICROSOFT REWARDS FARMER (Hidden Mode)
echo ==============================================
echo.
echo [1] Starting Farmer in Background...
echo     (Clone mode - Khong can dong Edge)
start "" pythonw farm_rewards.py

echo [2] Done! Script is running silently.
echo     Use 'View_Logs.bat' to see progress.
echo     Use 'Stop_Rewards.bat' to stop.
echo.
timeout /t 5

@echo off
cd /d "%~dp0"
echo ==============================================
echo   MICROSOFT REWARDS FARMER
echo ==============================================
echo.
echo Khoi dong giao dien GUI...
echo (Clone profile mode - Khong can dong Edge)
echo.
.venv\Scripts\python.exe launcher_gui.py
pause

@echo off
:: Tạo Desktop Shortcut cho Farm Menu
set SCRIPT_PATH=e:\MSrequat\farm_menu.pyw
set SHORTCUT_NAME=MS Rewards Menu.lnk
set DESKTOP=%USERPROFILE%\Desktop

echo Đang tạo shortcut Menu trên Desktop...

powershell -Command "$WshShell = New-Object -ComObject WScript.Shell; $Shortcut = $WshShell.CreateShortcut('%DESKTOP%\%SHORTCUT_NAME%'); $Shortcut.TargetPath = 'pythonw.exe'; $Shortcut.Arguments = '\"%SCRIPT_PATH%\"'; $Shortcut.WorkingDirectory = 'e:\MSrequat'; $Shortcut.Description = 'MS Rewards Farm Menu'; $Shortcut.Save()"

if exist "%DESKTOP%\%SHORTCUT_NAME%" (
    echo ✅ Đã tạo shortcut Menu thành công!
) else (
    echo ❌ Không thể tạo shortcut.
)

timeout /t 2 >nul

"""
farm/history.py - Points history tracking (JSON-based)
"""
import os
import json
from datetime import datetime, timedelta

HISTORY_FILE = os.path.join(os.path.dirname(os.path.dirname(os.path.abspath(__file__))), "points_history.json")


def load_history():
    """Load points history from JSON file."""
    try:
        if os.path.exists(HISTORY_FILE):
            with open(HISTORY_FILE, 'r', encoding='utf-8') as f:
                return json.load(f)
    except:
        pass
    return {"records": []}


def save_history(data):
    """Save points history to JSON file."""
    try:
        with open(HISTORY_FILE, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=2, ensure_ascii=False)
    except Exception as e:
        print(f"Error saving history: {e}")


def log_points(profile_name, points_before, points_after, farm_type="full"):
    """Log a farming session result."""
    data = load_history()
    record = {
        "date": datetime.now().strftime("%Y-%m-%d"),
        "time": datetime.now().strftime("%H:%M:%S"),
        "profile": profile_name,
        "before": points_before,
        "after": points_after,
        "earned": (points_after - points_before) if isinstance(points_before, int) and isinstance(points_after, int) else 0,
        "type": farm_type
    }
    data["records"].append(record)

    # Keep only last 90 days
    cutoff = (datetime.now() - timedelta(days=90)).strftime("%Y-%m-%d")
    data["records"] = [r for r in data["records"] if r.get("date", "") >= cutoff]

    save_history(data)
    return record


def get_today_stats():
    """Get today's stats grouped by profile."""
    data = load_history()
    today = datetime.now().strftime("%Y-%m-%d")

    stats = {}
    for r in data.get("records", []):
        if r.get("date") == today:
            profile = r.get("profile", "Unknown")
            if profile not in stats:
                stats[profile] = {"earned": 0, "sessions": 0, "last_points": 0}
            stats[profile]["earned"] += r.get("earned", 0)
            stats[profile]["sessions"] += 1
            if isinstance(r.get("after"), int):
                stats[profile]["last_points"] = r["after"]

    return stats


def get_weekly_total():
    """Get total points earned in last 7 days."""
    data = load_history()
    week_ago = (datetime.now() - timedelta(days=7)).strftime("%Y-%m-%d")

    total = 0
    for r in data.get("records", []):
        if r.get("date", "") >= week_ago:
            total += r.get("earned", 0)
    return total


def get_daily_totals(days=14):
    """Get daily totals for last N days."""
    data = load_history()

    daily = {}
    for i in range(days):
        d = (datetime.now() - timedelta(days=i)).strftime("%Y-%m-%d")
        daily[d] = 0

    for r in data.get("records", []):
        date = r.get("date", "")
        if date in daily:
            daily[date] += r.get("earned", 0)

    # Return ordered list
    return [(d, daily[d]) for d in sorted(daily.keys())]


def was_farmed_today(profile_name):
    """Check if a profile has already been farmed today (earned > 0)."""
    data = load_history()
    today = datetime.now().strftime("%Y-%m-%d")
    for r in data.get("records", []):
        if r.get("date") == today and r.get("profile") == profile_name:
            if r.get("earned", 0) > 0:
                return True
    return False


def get_profile_summary():
    """Get summary stats for each profile ever farmed."""
    data = load_history()
    summary = {}
    for r in data.get("records", []):
        profile = r.get("profile", "Unknown")
        if profile not in summary:
            summary[profile] = {"total_earned": 0, "sessions": 0, "last_date": "", "last_points": 0}
        summary[profile]["total_earned"] += r.get("earned", 0)
        summary[profile]["sessions"] += 1
        if r.get("date", "") >= summary[profile]["last_date"]:
            summary[profile]["last_date"] = r.get("date", "")
            if isinstance(r.get("after"), int):
                summary[profile]["last_points"] = r["after"]
    return summary


def get_streak_days():
    """Get number of consecutive days with farming activity."""
    data = load_history()
    dates_with_earnings = set()
    for r in data.get("records", []):
        if r.get("earned", 0) > 0:
            dates_with_earnings.add(r.get("date", ""))

    if not dates_with_earnings:
        return 0

    streak = 0
    check_date = datetime.now()
    for _ in range(365):
        date_str = check_date.strftime("%Y-%m-%d")
        if date_str in dates_with_earnings:
            streak += 1
            check_date -= timedelta(days=1)
        else:
            break
    return streak

"""
farm/activities.py - Daily set and more activities completion
Supports BOTH old UI (mee-rewards-*) and new UI (accordion cards).
"""
import time
import random
import logging
from selenium.webdriver.common.by import By
from selenium.webdriver.support.ui import WebDriverWait
from selenium.webdriver.support import expected_conditions as EC

from .utils import random_sleep, human_scroll, take_screenshot, check_and_recover_oom


def _is_new_ui(driver):
    """Detect if the dashboard is using the new accordion-based UI."""
    # New UI has accordion buttons with aria-labels like "Daily set", "Your activity"
    new_ui_indicators = [
        "button[aria-label='Daily set']",
        "button[aria-label='Your activity']",
        "button[aria-label='Achievements']",
    ]
    for selector in new_ui_indicators:
        try:
            elements = driver.find_elements(By.CSS_SELECTOR, selector)
            if elements:
                logging.info("[ACTIVITIES] Phát hiện UI MỚI (accordion-based)")
                return True
        except:
            pass

    # Also check for "See more tasks" text which is unique to new UI
    try:
        elements = driver.find_elements(By.XPATH, "//*[contains(text(), 'See more tasks')]")
        if elements:
            logging.info("[ACTIVITIES] Phát hiện UI MỚI (See more tasks)")
            return True
    except:
        pass

    logging.info("[ACTIVITIES] Sử dụng UI CŨ (mee-rewards)")
    return False


def _expand_new_ui_sections(driver):
    """Expand all accordion sections in the new UI."""
    # Try multiple possible section names (UI changes labels over time)
    sections = [
        "Daily set", "Your activity", "Achievements",
        "Your progress", "More activities", "More promotions",
    ]
    expanded = 0

    for section_name in sections:
        try:
            btn = driver.find_element(By.CSS_SELECTOR, f"button[aria-label='{section_name}']")
            # Check if already expanded
            is_expanded = btn.get_attribute("aria-expanded")
            if is_expanded == "false" or is_expanded is None:
                driver.execute_script("arguments[0].scrollIntoView({behavior: 'smooth', block: 'center'});", btn)
                time.sleep(0.5)
                driver.execute_script("arguments[0].click();", btn)
                time.sleep(random.uniform(1, 2))
                expanded += 1
                logging.info(f"   [NEW UI] Expanded: {section_name}")
        except:
            pass

    # Fallback: find ALL buttons with aria-expanded="false" and expand them
    if expanded == 0:
        try:
            buttons = driver.find_elements(By.CSS_SELECTOR, "button[aria-expanded='false']")
            for btn in buttons:
                try:
                    label = btn.get_attribute("aria-label") or btn.text
                    driver.execute_script("arguments[0].scrollIntoView({behavior: 'smooth', block: 'center'});", btn)
                    time.sleep(0.5)
                    driver.execute_script("arguments[0].click();", btn)
                    time.sleep(random.uniform(1, 2))
                    expanded += 1
                    logging.info(f"   [NEW UI] Expanded (fallback): {label}")
                except:
                    pass
        except:
            pass

    # Also click "See more tasks" if visible
    try:
        see_more = driver.find_elements(By.XPATH, "//*[contains(text(), 'See more tasks')]")
        for btn in see_more:
            if btn.is_displayed():
                driver.execute_script("arguments[0].click();", btn)
                time.sleep(1)
                logging.info("   [NEW UI] Clicked 'See more tasks'")
                break
    except:
        pass

    return expanded


def _get_new_ui_task_cards(driver):
    """Get all task cards from the new UI after expanding sections."""
    cards = []
    seen_texts = set()

    # Progress button keywords — these are NOT task cards, they open modals
    progress_keywords = ["search:", "activity:", "check-in:", "how to activate", "check in:"]
    # X/X completion pattern (e.g. "3/3", "7/7")
    import re as _re
    _xofx_pat = _re.compile(r'(\d+)/(\d+)')

    def _is_progress_complete(text: str) -> bool:
        """Check if progress text shows X/X = fully completed."""
        for num, denom in _xofx_pat.findall(text):
            if num == denom and int(num) > 0:
                return True
        return False

    def _is_progress_card(el):
        """Check if element is a progress tracking button (not a clickable task)."""
        try:
            tag = el.tag_name.lower()
            text = (el.text or "").lower()
            # <button> elements with progress keywords are trackers, not tasks
            if tag == 'button' and any(kw in text for kw in progress_keywords):
                return True
            # <div> streak cards showing X/X (already completed) — skip them
            if tag == 'div' and _is_progress_complete(text):
                return True
        except:
            pass
        return False


    # Primary: Find elements with 'CardRewards' in class name
    # Actual DOM class: "mai:rounded-cornerCardRewards"
    # This matches both <a> task cards AND <button> progress cards, so filter
    try:
        elements = driver.find_elements(By.CSS_SELECTOR, "[class*='CardRewards']")
        for el in elements:
            if _is_progress_card(el):
                continue
            text = (el.text or "").strip()[:60]
            if text and text not in seen_texts:
                seen_texts.add(text)
                cards.append(el)
                logging.info(f"   [CARDS] Found: <{el.tag_name}> {text[:40]}")
    except:
        pass

    # Secondary: Find cards by looking inside Daily set section specifically
    if not cards:
        try:
            daily_btn = driver.find_element(By.CSS_SELECTOR, "button[aria-label='Daily set']")
            # Navigate up to section container
            container = daily_btn.find_element(By.XPATH, "./..")
            children = container.find_elements(By.CSS_SELECTOR, "a[href]")
            for child in children:
                text = (child.text or "").strip()[:60]
                href = child.get_attribute("href") or ""
                if text and text not in seen_texts and "dashboard" not in href:
                    seen_texts.add(text)
                    cards.append(child)
        except:
            pass

    # Tertiary fallback: find ANY <a> or <div> containing point values (NOT buttons)
    if not cards:
        try:
            point_xpath = "//*[contains(text(), '+10') or contains(text(), '+5') or contains(text(), '+30')]"
            all_elements = driver.find_elements(By.XPATH, point_xpath)
            for el in all_elements:
                tag = el.tag_name.lower()
                if tag in ('a', 'div'):  # Exclude <button> — those are progress cards
                    text = (el.text or "").strip()[:60]
                    if text and len(text) > 5 and text not in seen_texts:
                        seen_texts.add(text)
                        cards.append(el)
        except:
            pass

    logging.info(f"[CARDS] Total task cards found: {len(cards)}")
    return cards


def _is_card_completed_new_ui(card):
    """Check if a new UI card is already completed."""
    import re
    try:
        card_html = card.get_attribute("outerHTML") or ""
        card_text = (card.text or "").lower()

        # 1. Check HTML for checkmark/completion icons
        completed_indicators = ["\u2713", "check", "completed", "Completed", "SkypeCircleCheck"]
        for indicator in completed_indicators:
            if indicator in card_html:
                return True

        # 2. Check aria attributes
        aria_label = card.get_attribute("aria-label") or ""
        if "completed" in aria_label.lower() or "done" in aria_label.lower():
            return True

        # 3. Check progress X/X patterns — e.g. "search: 3/3", "activity: 2/2"
        #    If the progress numerator == denominator, the task is complete
        xofx_matches = re.findall(r'(\d+)/(\d+)', card_text)
        for num, denom in xofx_matches:
            if num == denom and int(num) > 0:
                return True

        # 4. Check for "Nice work" text that appears on completed streak cards
        if "nice work" in card_text:
            return True

    except:
        pass
    return False


def solve_potential_quiz(driver):
    try:
        start_btns = driver.find_elements(By.XPATH, "//input[@value='Start playing'] | //span[contains(@class, 'rq_button')]")
        if start_btns:
            logging.info("   -> Phát hiện Quiz/Poll, bấm Start...")
            try:
                driver.execute_script("arguments[0].click();", start_btns[0])
                time.sleep(3)
            except: pass

        for step in range(15): 
            options = driver.find_elements(By.CSS_SELECTOR, ".btOption, .rq_option, .wk_OptionClick, .b_cards, #currentQuestionContainer .b_answer")
            if not options:
                if step == 0: continue 
                else: break

            try:
                choice = random.choice(options)
                driver.execute_script("arguments[0].click();", choice)
                time.sleep(random.uniform(2, 4))

                if driver.find_elements(By.CSS_SELECTOR, ".btPollResult, .cico"):
                    logging.info("   -> Quiz/Poll hoàn thành.")
                    break
            except:
                pass
    except:
        pass


